class ErrorBoundary extends StatelessWidget {
  final Widget child;
  final Widget Function(FlutterErrorDetails) fallback;

  @override
  Widget build(BuildContext context) {
    ErrorWidget.builder = (details) {
      return fallback(details);
    };
    return child;
  }
}

class ApiClient {
  Future<T> request<T>(Future<T> Function() apiCall) async {
    try {
      return await apiCall().timeout(const Duration(seconds: 30));
    } on SocketException {
      throw NetworkFailure('No internet connection');
    } on TimeoutException {
      throw NetworkFailure('Request timed out');
    } on DioException catch (e) {
      throw ServerFailure(_mapDioError(e));
    }
  }
}

