Future<T> retryWithBackoff<T>(Future<T> Function() fn, {int maxAttempts = 3}) async {
  int attempt = 0;
  while (true) {
    try {
      attempt++;
      return await fn();
    } catch (e) {
      if (attempt >= maxAttempts || !_isRetryable(e)) rethrow;
      await Future.delayed(Duration(milliseconds: 200 * pow(2, attempt).toInt()));
    }
  }
}
bool _isRetryable(dynamic e) => e is SocketException || (e is DioException && e.response?.statusCode == 503);

class LoginFormBloc extends FormBloc {
  final email = TextFieldBloc(validators: [FieldBlocValidators.required, FieldBlocValidators.email]);
  final password = TextFieldBloc(validators: [FieldBlocValidators.required, _minLength(8)]);

  @override
  void onSubmitting() async {
    try {
      await authRepo.login(email.value, password.value);
      emitSuccess();
    } on InvalidCredentialsException {
      emitFailure(failureResponse: 'Invalid email or password');
    }
  }
}

