}

class OfflineQueue {
  final HiveBox _box;

  Future<void> enqueue(PendingAction action) async {
    await _box.add(action.toJson());
  }

  Future<void> processQueue() async {
    final pending = _box.values.toList();
    for (final item in pending) {
      try {
        await _executeAction(PendingAction.fromJson(item));
        await _box.delete(item.key);
      } catch (e) {
        break; // Stop processing, retry later
      }
    }
  }
}

Future<String?> getBatteryLevel() async {
  try {
    final result = await platform.invokeMethod<int>('getBatteryLevel');
    return '$result%';
  } on PlatformException catch (e) {
    debugPrint('Platform error: ${e.code} - ${e.message}');
    return null; // Graceful fallback
  } on MissingPluginException {
    debugPrint('Plugin not available on this platform');
    return null;
  }
}

enum Status { initial, loading, success, error }

class AsyncValue<T> {
  final Status status;
  final T? data;
  final String? error;

  bool get isLoading => status == Status.loading;
  bool get hasError => error != null;
  bool get hasData => data != null;
}

