void showErrorSnackbar(BuildContext context, String message, {VoidCallback? onRetry}) {
  ScaffoldMessenger.of(context).showSnackBar(
    SnackBar(
      content: Text(message),
      backgroundColor: Theme.of(context).colorScheme.error,
      action: onRetry != null ? SnackBarAction(label: 'Retry', onPressed: onRetry) : null,
    ),
  );
}

Failure mapDioError(DioException e) {
  switch (e.response?.statusCode) {
    case 400: return ValidationFailure(_parseErrors(e.response?.data));
    case 401: return AuthFailure('Session expired. Please login again.');
    case 403: return AuthFailure('You do not have permission.');
    case 404: return NotFoundFailure('Resource not found.');
    case 429: return RateLimitFailure('Too many requests. Please wait.');
    case >= 500: return ServerFailure('Server error. Please try again later.');
    default: return NetworkFailure(e.message ?? 'Connection failed');
  }
}

class CrashReporter {
  void addBreadcrumb(String category, String message, {Map<String, dynamic>? data}) {
    Sentry.addBreadcrumb(Breadcrumb(
      category: category,
      message: message,
      data: data,
      timestamp: DateTime.now(),
    ));
  }

  void setUserContext(String userId) {
    Sentry.configureScope((scope) {
      scope.setUser(SentryUser(id: userId));
    });
  }
}

class FeatureAvailability {
  static Future<bool> isAvailable(String feature) async {
    try {
      switch (feature) {
        case 'biometric': return await LocalAuthentication().canCheckBiometrics;
        case 'camera': return await Permission.camera.isGranted;
        case 'location': return await Geolocator.isLocationServiceEnabled();
        default: return false;
      }
    } catch (_) {
      return false; // Feature unavailable, degrade gracefully
    }
  }
}
